#include <bits/stdc++.h>
using namespace std;
int main(){
    int a[1000],b[1000];int n,lena=1,lenb;
    cin>>n;
    for(int i=1;i<1000;i++)a[i]=0;
    for(int i=1;i<=n;i++){
        for(int j=1;j<1000;j++)b[j]=0;
        b[1]=1;lenb=1;
        for(int j=1;j<=i;j++){
        	int x=0;
            for(int z=1;z<=lenb;z++){
                b[z]=b[z]*j+x;
                x=b[z]/10;
                b[z]%=10;
            }
            b[lenb+1]+=x;
            if(x>9){
            	lenb+=2;
            	b[lenb]+=b[lenb-1]/10;
            	b[lenb-1]%=10;
			}else if(x>0)lenb++;
            //while(b[lenb+1]>0){
            //	b[lenb+1]+=b[lenb]/10;
            //    b[lenb]%=10;
            //	lenb++;
			//}
			//for(int j=lenb;j>0;j--)cout<<b[j];
        	//cout<<endl;
        }
        //for(int j=lenb;j>0;j--)cout<<b[j];
        //cout<<endl;
        lena=max(lena,lenb);
        //cout<<"len:"<<lena<<endl;
        for(int j=1;j<=lena;j++){
            a[j]+=b[j];
            a[j+1]+=a[j]/10;
            a[j]%=10;
        }
        if(a[lena+1])lena++;
        //cout<<"a:";
        //for(int i=lena;i>0;i--)cout<<a[i];
        //cout<<endl;
    }
    for(int i=lena;i>0;i--)cout<<a[i];
    return 0;
}
